/**
 * @summary Export scenario program as GTFS zip
 */
export const getExportScenarioGtfsUrl = (
  id: string,
  programId: string,
  params?: ExportScenarioGtfsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/scenarios/${id}/programs/${programId}/export-gtfs?${stringifiedParams}`
    : `/api/scenarios/${id}/programs/${programId}/export-gtfs`;
};

